@startuml
title RECORDINGQUEUE's Class Diagram

package "com" {
  package "voicenotes" {
    package "view" {
      package "utils" {
        package "recordingqueue" {
          class "ThreadQueue" {
            <<C>>
            + queue : List<String>
            + endLoop : boolean
            + context : Context
            + initialize()
            + addElement()
            + stopQueueLoop()
            + startQueueLoop()
            - processLoop()
          }

          class "Transcriber" {
            <<C>>
            + decoder : Decoder
            + c : Config
            + audioOutputStream : FileOutputStream
            + sampleRate : int
            + minBufferSize : int
            + recorder : AudioRecord
            + audioStorageFilePath : String
            + context : Context
            + initialize()
            - short2byte()
            + transcribe()
          }
        }
      }
    }
  }
}

@enduml
